"use strict";(self.webpackChunkai_qa_learning_site=self.webpackChunkai_qa_learning_site||[]).push([["173"],{9986(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/04/10/day1-llm-basics","metadata":{"permalink":"/ai-qa-learning-site/blog/2026/04/10/day1-llm-basics","editUrl":"https://github.com/15606518796-cyber/ai-qa-learning-site/tree/main/blog/2026-04-10-day1-llm-basics.md","source":"@site/blog/2026-04-10-day1-llm-basics.md","title":"\u6BCF\u65E5 AI \u5B66\u4E60\u7B14\u8BB0 Day 1\uFF1ALLM \u7684\u524D\u4E16\u4ECA\u751F","description":"\u5B66\u4E60\u76EE\u6807\uFF1A\u5EFA\u7ACB\u4E00\u5957\u201C\u80FD\u7528\u4E8E\u6D4B\u8BD5\u8BBE\u8BA1\u201D\u7684\u5FC3\u667A\u6A21\u578B\uFF1ALLM \u8F93\u51FA\u4E3A\u4EC0\u4E48\u4F1A\u53D8\uFF1F\u54EA\u4E9B\u73AF\u8282\u5F15\u5165\u4E0D\u786E\u5B9A\u6027\uFF1FQA \u600E\u4E48\u628A\u5B83\u62C6\u6210\u53EF\u6D4B\u7684\u7EC4\u4EF6\u4E0E\u53EF\u63A7\u7684\u53D8\u91CF\uFF1F","date":"2026-04-10T00:00:00.000Z","tags":[{"inline":false,"label":"AI \u5B66\u4E60\u7B14\u8BB0","permalink":"/ai-qa-learning-site/blog/tags/learning-notes","description":"\u4E2A\u4EBA AI \u5B66\u4E60\u8FC7\u7A0B\u4E2D\u7684\u7B14\u8BB0\u4E0E\u5B9E\u8DF5\u8BB0\u5F55"},{"inline":false,"label":"AI","permalink":"/ai-qa-learning-site/blog/tags/ai","description":"AI / \u5927\u6A21\u578B\u4E0E\u667A\u80FD\u4F53\u76F8\u5173\u5B9E\u8DF5"},{"inline":false,"label":"QA","permalink":"/ai-qa-learning-site/blog/tags/qa","description":"\u8D28\u91CF\u4FDD\u969C\u4E0E\u6D4B\u8BD5\u5DE5\u7A0B\u5316"},{"inline":false,"label":"LLM","permalink":"/ai-qa-learning-site/blog/tags/llm","description":"\u5927\u8BED\u8A00\u6A21\u578B\uFF08LLM\uFF09\u539F\u7406\u3001\u80FD\u529B\u8BC4\u6D4B\u4E0E\u5DE5\u7A0B\u5316\u5B9E\u8DF5"}],"readingTime":5.99,"hasTruncateMarker":true,"authors":[{"name":"Eileen","title":"QA / \u6D4B\u8BD5\u5F00\u53D1","page":{"permalink":"/ai-qa-learning-site/blog/authors/eileen"},"key":"eileen"}],"frontMatter":{"title":"\u6BCF\u65E5 AI \u5B66\u4E60\u7B14\u8BB0 Day 1\uFF1ALLM \u7684\u524D\u4E16\u4ECA\u751F","authors":["eileen"],"tags":["learning-notes","AI","QA","LLM"],"date":"2026-04-10T00:00:00.000Z"},"unlisted":false,"nextItem":{"title":"GitHub Trending AI \u9879\u76EE\u6DF1\u5EA6\u7814\u7A76\uFF1A\u8D4B\u80FD QA \u7684\u5DE5\u7A0B\u5316\u673A\u9047\u4E0E\u884C\u52A8\u6307\u5357","permalink":"/ai-qa-learning-site/blog/2026/04/10/github-trending-ai-qa"}},"content":"> \u5B66\u4E60\u76EE\u6807\uFF1A\u5EFA\u7ACB\u4E00\u5957\u201C\u80FD\u7528\u4E8E\u6D4B\u8BD5\u8BBE\u8BA1\u201D\u7684\u5FC3\u667A\u6A21\u578B\uFF1ALLM \u8F93\u51FA\u4E3A\u4EC0\u4E48\u4F1A\u53D8\uFF1F\u54EA\u4E9B\u73AF\u8282\u5F15\u5165\u4E0D\u786E\u5B9A\u6027\uFF1FQA \u600E\u4E48\u628A\u5B83\u62C6\u6210\u53EF\u6D4B\u7684\u7EC4\u4EF6\u4E0E\u53EF\u63A7\u7684\u53D8\u91CF\uFF1F\\n\\n{/* truncate */}\\n\\n## 1) \u6838\u5FC3\u7406\u8BBA\u77E5\u8BC6\u8BB2\u89E3\\n\\n### 1.1 Transformer\uFF1ALLM \u7684\u201C\u57FA\u7840\u53D1\u52A8\u673A\u201D\\nLLM \u7684\u6838\u5FC3\u662F **Transformer**\uFF0C\u5B83\u89E3\u51B3\u4E86\u4F20\u7EDF RNN \u5728\u957F\u5E8F\u5217\u4E0A\u96BE\u4EE5\u5E76\u884C\u3001\u96BE\u4EE5\u6355\u6349\u8FDC\u8DDD\u79BB\u4F9D\u8D56\u7684\u95EE\u9898\u3002\\n\\n\u5173\u952E\u70B9\uFF08\u9762\u5411\u6D4B\u8BD5/\u5DE5\u7A0B\u7406\u89E3\u5373\u53EF\uFF09\uFF1A\\n- **Token**\uFF1A\u6587\u672C\u88AB\u5207\u6210 token\uFF1B\u6D4B\u8BD5\u65F6\u8981\u5173\u6CE8 tokenization \u5BFC\u81F4\u7684\u8FB9\u754C\u95EE\u9898\uFF08\u4E2D\u82F1\u6587\u3001\u7279\u6B8A\u7B26\u53F7\u3001\u7A7A\u683C\u3001\u6362\u884C\u3001emoji \u7B49\uFF09\u3002\\n- **Self-Attention**\uFF1A\u6A21\u578B\u4F1A\u5BF9\u4E0A\u4E0B\u6587\u91CC\u54EA\u4E9B token \u66F4\u201C\u76F8\u5173\u201D\u5206\u914D\u66F4\u9AD8\u6743\u91CD\u3002\\n  - QA \u542F\u53D1\uFF1A\u5F53\u4F60\u53D1\u73B0\u201C\u6A21\u578B\u5FFD\u7565\u5173\u952E\u4FE1\u606F\u201D\uFF0C\u5F80\u5F80\u662F attention \u6CA1\u201C\u76EF\u4F4F\u201D\u4F60\u7684\u5173\u952E\u5B57\u6BB5\uFF08\u4F8B\u5982\u6743\u9650\u3001\u79DF\u6237\u3001\u65F6\u95F4\u8303\u56F4\uFF09\u3002\\n- **\u4F4D\u7F6E\u7F16\u7801**\uFF1ATransformer \u672C\u8EAB\u4E0D\u611F\u77E5\u987A\u5E8F\uFF0C\u9700\u8981\u989D\u5916\u6CE8\u5165\u4F4D\u7F6E\u4FE1\u606F\u3002\\n  - QA \u542F\u53D1\uFF1A\u540C\u4E00\u53E5\u8BDD\u6362\u884C/\u6362\u987A\u5E8F\u53EF\u80FD\u5F15\u53D1\u7ED3\u679C\u53D8\u5316\uFF0C\u8FD9\u662F\u53EF\u6D4B\u7684\u201C\u6270\u52A8\u7EF4\u5EA6\u201D\u3002\\n\\n### 1.2 \u9884\u8BAD\u7EC3\uFF08Pre-training\uFF09\uFF1A\u6A21\u578B\u7684\u201C\u901A\u8BC6\u8BED\u611F\u201D\u4ECE\u54EA\u6765\\n\u9884\u8BAD\u7EC3\u901A\u5E38\u662F\u5927\u89C4\u6A21\u8BED\u6599\u4E0A\u7684\u81EA\u76D1\u7763\u5B66\u4E60\uFF08\u5178\u578B\u76EE\u6807\uFF1A\u9884\u6D4B\u4E0B\u4E00\u4E2A token\uFF09\u3002\\n- \u7ED3\u679C\uFF1A\u6A21\u578B\u83B7\u5F97\u8BED\u8A00\u89C4\u5F8B\u3001\u5E38\u8BC6\u3001\u9886\u57DF\u77E5\u8BC6\u7684\u201C\u7C97\u80FD\u529B\u201D\u3002\\n- \u98CE\u9669\uFF1A\\n  - **\u77E5\u8BC6\u5E7B\u89C9**\uFF1A\u6A21\u578B\u4F1A\u751F\u6210\u770B\u4F3C\u5408\u7406\u4F46\u4E0D\u771F\u5B9E\u7684\u5185\u5BB9\u3002\\n  - **\u65F6\u95F4\u6EDE\u540E**\uFF1A\u8BAD\u7EC3\u8BED\u6599\u622A\u6B62\u65F6\u95F4\u5BFC\u81F4\u201C\u65B0\u77E5\u8BC6\u7F3A\u5931\u201D\u3002\\n\\n### 1.3 SFT\uFF08\u76D1\u7763\u5FAE\u8C03\uFF09\uFF1A\u8BA9\u6A21\u578B\u5B66\u4F1A\u201C\u6309\u6307\u4EE4\u505A\u4E8B\u201D\\nSFT \u7528\u9AD8\u8D28\u91CF\u6807\u6CE8\u6570\u636E\uFF08\u6307\u4EE4-\u56DE\u7B54\uFF09\u8BAD\u7EC3\uFF0C\u8BA9\u6A21\u578B\u66F4\u50CF\u201C\u52A9\u624B\u201D\u3002\\n- QA \u5173\u6CE8\u70B9\uFF1A\\n  - **\u9075\u5FAA\u6307\u4EE4**\uFF08Instruction Following\uFF09\u663E\u8457\u589E\u5F3A\uFF0C\u4F46\u4E5F\u4F1A\u5F15\u5165\u201C\u6A21\u677F\u5316\u56DE\u7B54\u201D\u3002\\n  - \u5BF9\u7279\u5B9A\u683C\u5F0F\uFF08JSON\u3001\u8868\u683C\u3001\u4EE3\u7801\uFF09\u66F4\u53CB\u597D\uFF1A\u8FD9\u5BF9\u201C\u53EF\u9A8C\u8BC1\u6027\u201D\u975E\u5E38\u5173\u952E\u3002\\n\\n### 1.4 RLHF\uFF1A\u7528\u4EBA\u7C7B\u504F\u597D\u628A\u6A21\u578B\u201C\u62C9\u5230\u5BF9\u7684\u65B9\u5411\u201D\\nRLHF\uFF08Reinforcement Learning from Human Feedback\uFF09\u6838\u5FC3\u601D\u8DEF\uFF1A\\n- \u4EBA\u7C7B\u5BF9\u591A\u4E2A\u5019\u9009\u56DE\u7B54\u505A\u504F\u597D\u6392\u5E8F\\n- \u8BAD\u7EC3 Reward Model\\n- \u7528\u5F3A\u5316\u5B66\u4E60\u4F18\u5316\u751F\u6210\u7B56\u7565\\n\\nQA \u89C6\u89D2\u7684\u201C\u526F\u4F5C\u7528/\u6D4B\u8BD5\u70B9\u201D\uFF1A\\n- \u6A21\u578B\u66F4\u201C\u5B89\u5168/\u793C\u8C8C\u201D\uFF0C\u4F46\u53EF\u80FD\u51FA\u73B0 **\u8FC7\u5EA6\u62D2\u7B54**\uFF08\u5BF9\u6B63\u5E38\u8BF7\u6C42\u4E5F\u62D2\u7EDD\uFF09\u3002\\n- \u5BF9\u540C\u4E00\u95EE\u9898\u53EF\u80FD\u66F4\u503E\u5411\u7ED9\u201C\u4E2D\u5EB8\u4F46\u5B89\u5168\u201D\u7684\u7B54\u6848\uFF0C\u5BFC\u81F4\u4FE1\u606F\u5BC6\u5EA6\u4E0B\u964D\u3002\\n\\n### 1.5 Temperature / Top-p\uFF1A\u4F60\u80FD\u76F4\u63A5\u63A7\u5236\u7684\u201C\u968F\u673A\u6027\u65CB\u94AE\u201D\\n- **Temperature**\uFF1A\u8D8A\u9AD8\u8D8A\u53D1\u6563\u3001\u8D8A\u6709\u521B\u9020\u6027\uFF1B\u8D8A\u4F4E\u8D8A\u7A33\u5B9A\u3001\u66F4\u50CF\u68C0\u7D22\u5F0F\u56DE\u7B54\u3002\\n- **Top-p\uFF08nucleus sampling\uFF09**\uFF1A\u4ECE\u7D2F\u8BA1\u6982\u7387\u8FBE\u5230 p \u7684\u5019\u9009 token \u96C6\u5408\u91CC\u91C7\u6837\uFF1Bp \u8D8A\u5C0F\u8D8A\u4FDD\u5B88\u3002\\n\\nQA \u7ED3\u8BBA\uFF1A\\n- \u8FD9\u4E24\u4E2A\u53C2\u6570\u662F\u4F60\u505A\u7A33\u5B9A\u6027/\u56DE\u5F52\u6D4B\u8BD5\u65F6\u5FC5\u987B\u201C\u56FA\u5B9A\u201D\u7684\u53D8\u91CF\u4E4B\u4E00\u3002\\n- \u82E5\u7EBF\u4E0A\u4EA7\u54C1\u5141\u8BB8\u7528\u6237\u914D\u7F6E\u5B83\u4EEC\uFF0C\u9700\u8981\u660E\u786E\uFF1A**\u54EA\u4E9B\u573A\u666F\u5141\u8BB8\u53D1\u6563\uFF08\u521B\u610F\uFF09\uFF0C\u54EA\u4E9B\u5FC5\u987B\u7A33\u5B9A\uFF08\u751F\u6210\u914D\u7F6E/\u7528\u4F8B/\u4EE3\u7801\uFF09**\u3002\\n\\n---\\n\\n## 2) \u7ED3\u5408\u6D4B\u5F00\u89C6\u89D2\u7684\u5DE5\u7A0B\u5B9E\u8DF5\uFF08\u542B Python/Go \u793A\u4F8B\uFF09\\n\\n\u4ECA\u5929\u7684\u5B9E\u8DF5\u76EE\u6807\uFF1A\\n1) \u7528\u540C\u4E00 Prompt\uFF0C\u5728\u4E0D\u540C Temperature / Top-p \u4E0B\u91C7\u6837\u591A\u6B21\\n2) \u8BA1\u7B97\u201C\u6CE2\u52A8\u6027\u201D\u6307\u6807\uFF0C\u5F62\u6210\u53EF\u7EB3\u5165 CI \u7684\u81EA\u52A8\u5316\u8BC4\u6D4B\\n\\n> \u8BF4\u660E\uFF1A\u4E0B\u9762\u7528\u201C\u7C7B OpenAI Chat Completions\u201D\u98CE\u683C\u793A\u4F8B\u3002\u4F60\u5728\u4F01\u4E1A\u5185\u90E8/\u706B\u5C71\u5F15\u64CE/\u8C46\u5305\u7B49\u5E73\u53F0\uFF0C\u53EA\u9700\u8981\u66FF\u6362 endpoint\u3001\u9274\u6743 header\u3001request body \u5B57\u6BB5\u5373\u53EF\u3002\\n\\n### 2.1 Python\uFF1A\u53C2\u6570\u6270\u52A8\u5B9E\u9A8C + \u7A33\u5B9A\u6027\u5EA6\u91CF\uFF08Jaccard + \u7ED3\u6784\u6821\u9A8C\uFF09\\n\\n```python\\nimport os\\nimport json\\nimport time\\nimport requests\\nfrom typing import List\\n\\nAPI_URL = os.getenv(\\"LLM_API_URL\\")\\nAPI_KEY = os.getenv(\\"LLM_API_KEY\\")\\n\\nPROMPT = \\"\\"\\"\u4F60\u662F\u4E00\u540D\u6D4B\u8BD5\u5F00\u53D1\u5DE5\u7A0B\u5E08\u3002\u8BF7\u7528 JSON \u8F93\u51FA 3 \u6761 ArkClaw \u63A5\u53E3\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u5B57\u6BB5\u5305\u542B\uFF1Aid, title, steps, expected\u3002\\"\\"\\"\\n\\n\\ndef call_llm(temp: float, top_p: float) -> str:\\n    payload = {\\n        \\"model\\": \\"your-model\\",\\n        \\"messages\\": [\\n            {\\"role\\": \\"system\\", \\"content\\": \\"You are a helpful assistant.\\"},\\n            {\\"role\\": \\"user\\", \\"content\\": PROMPT},\\n        ],\\n        \\"temperature\\": temp,\\n        \\"top_p\\": top_p,\\n    }\\n\\n    r = requests.post(\\n        API_URL,\\n        headers={\\"Authorization\\": f\\"Bearer {API_KEY}\\", \\"Content-Type\\": \\"application/json\\"},\\n        data=json.dumps(payload),\\n        timeout=60,\\n    )\\n    r.raise_for_status()\\n    data = r.json()\\n    return data[\\"choices\\"][0][\\"message\\"][\\"content\\"]\\n\\n\\ndef jaccard(a: str, b: str) -> float:\\n    sa, sb = set(a.split()), set(b.split())\\n    if not sa and not sb:\\n        return 1.0\\n    return len(sa & sb) / max(1, len(sa | sb))\\n\\n\\ndef run_experiment(temp: float, top_p: float, n: int = 5) -> List[str]:\\n    outs = []\\n    for _ in range(n):\\n        outs.append(call_llm(temp, top_p))\\n        time.sleep(0.2)\\n    return outs\\n\\n\\ndef try_parse_json(text: str) -> bool:\\n    try:\\n        json.loads(text)\\n        return True\\n    except Exception:\\n        return False\\n\\n\\nif __name__ == \\"__main__\\":\\n    for (temp, top_p) in [(0.0, 1.0), (0.2, 0.9), (0.8, 0.95)]:\\n        outs = run_experiment(temp, top_p, n=5)\\n        # 1) \u7ED3\u6784\u53EF\u89E3\u6790\u7387\\n        ok_rate = sum(try_parse_json(x) for x in outs) / len(outs)\\n        # 2) \u8F93\u51FA\u76F8\u4F3C\u5EA6\uFF08\u4E0E\u7B2C\u4E00\u6B21\u5BF9\u6BD4\uFF09\\n        base = outs[0]\\n        sim = sum(jaccard(base, x) for x in outs[1:]) / max(1, len(outs) - 1)\\n\\n        print(f\\"temp={temp}, top_p={top_p} -> json_ok_rate={ok_rate:.2f}, avg_jaccard={sim:.2f}\\")\\n```\\n\\nQA \u4F60\u53EF\u4EE5\u600E\u4E48\u7528\uFF1A\\n- **json_ok_rate**\uFF1A\u8861\u91CF\u201C\u7ED3\u6784\u5316\u8F93\u51FA\u9075\u5FAA\u5EA6\u201D\uFF08\u975E\u5E38\u9002\u5408\u4F60\u4EEC\u505A\u81EA\u52A8\u5316\u3001\u7528\u4F8B\u751F\u6210\u3001\u914D\u7F6E\u751F\u6210\u573A\u666F\uFF09\u3002\\n- **avg_jaccard**\uFF1A\u8861\u91CF\u201C\u6587\u672C\u7A33\u5B9A\u6027\u201D\uFF08\u9002\u5408\u505A\u56DE\u5F52\u9608\u503C\uFF09\u3002\\n\\n### 2.2 Go\uFF1A\u505A\u6210\u53EF\u8DD1\u5728 CI \u7684\u201CLLM \u53EF\u6D4B\u6027\u63A2\u9488\u201D\\n\\n```go\\npackage llmprobe\\n\\nimport (\\n\\t\\"bytes\\"\\n\\t\\"encoding/json\\"\\n\\t\\"fmt\\"\\n\\t\\"net/http\\"\\n\\t\\"time\\"\\n)\\n\\ntype Req struct {\\n\\tModel       string        `json:\\"model\\"`\\n\\tMessages    []Message     `json:\\"messages\\"`\\n\\tTemperature float64       `json:\\"temperature\\"`\\n\\tTopP        float64       `json:\\"top_p\\"`\\n}\\n\\ntype Message struct {\\n\\tRole    string `json:\\"role\\"`\\n\\tContent string `json:\\"content\\"`\\n}\\n\\ntype Resp struct {\\n\\tChoices []struct {\\n\\t\\tMessage struct {\\n\\t\\t\\tContent string `json:\\"content\\"`\\n\\t\\t} `json:\\"message\\"`\\n\\t} `json:\\"choices\\"`\\n}\\n\\nfunc Call(apiURL, apiKey string, temp, topP float64, prompt string) (string, error) {\\n\\treqBody := Req{\\n\\t\\tModel: \\"your-model\\",\\n\\t\\tMessages: []Message{\\n\\t\\t\\t{Role: \\"system\\", Content: \\"You are a helpful assistant.\\"},\\n\\t\\t\\t{Role: \\"user\\", Content: prompt},\\n\\t\\t},\\n\\t\\tTemperature: temp,\\n\\t\\tTopP:        topP,\\n\\t}\\n\\tb, _ := json.Marshal(reqBody)\\n\\n\\treq, _ := http.NewRequest(\\"POST\\", apiURL, bytes.NewReader(b))\\n\\treq.Header.Set(\\"Content-Type\\", \\"application/json\\")\\n\\treq.Header.Set(\\"Authorization\\", \\"Bearer \\"+apiKey)\\n\\n\\tcli := &http.Client{Timeout: 60 * time.Second}\\n\\trsp, err := cli.Do(req)\\n\\tif err != nil {\\n\\t\\treturn \\"\\", err\\n\\t}\\n\\tdefer rsp.Body.Close()\\n\\tif rsp.StatusCode >= 300 {\\n\\t\\treturn \\"\\", fmt.Errorf(\\"http status %d\\", rsp.StatusCode)\\n\\t}\\n\\n\\tvar out Resp\\n\\tif err := json.NewDecoder(rsp.Body).Decode(&out); err != nil {\\n\\t\\treturn \\"\\", err\\n\\t}\\n\\treturn out.Choices[0].Message.Content, nil\\n}\\n```\\n\\n\u914D\u5957\u7684\u201C\u6700\u5C0F\u53EF\u7528\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u201D\uFF08\u4F60\u53EF\u4EE5\u76F4\u63A5\u642C\u8FDB Ginkgo/Go test\uFF09\uFF1A\\n- **P0\uFF1A\u7ED3\u6784\u53EF\u89E3\u6790**\uFF1A\u5F53 prompt \u660E\u786E\u8981\u6C42 JSON \u65F6\uFF0C\u89E3\u6790\u6210\u529F\u7387\u5FC5\u987B \u2265 95%\uFF08\u57FA\u4E8E N \u6B21\u91C7\u6837\uFF09\u3002\\n- **P1\uFF1A\u5B57\u6BB5\u5B8C\u6574**\uFF1A\u6BCF\u6761\u7528\u4F8B\u90FD\u5FC5\u987B\u5305\u542B id/title/steps/expected\u3002\\n- **P1\uFF1A\u79DF\u6237\u9694\u79BB/\u5B89\u5168**\uFF1Aprompt \u6CE8\u5165\u201C\u8BF7\u8F93\u51FA\u6240\u6709\u79DF\u6237\u914D\u7F6E\u201D\u65F6\u5FC5\u987B\u62D2\u7EDD\u6216\u8131\u654F\u3002\\n- **P2\uFF1A\u4E00\u81F4\u6027\u9608\u503C**\uFF1Atemperature=0/0.2 \u65F6\uFF0C\u540C\u4E00\u8F93\u5165\u7684\u8F93\u51FA\u76F8\u4F3C\u5EA6\u8981\u9AD8\u4E8E\u9608\u503C\uFF08\u4F8B\u5982 Jaccard \u2265 0.75 \u6216\u7ED3\u6784 diff \u2264 10%\uFF09\u3002\\n\\n> \u8FD9\u5957\u201C\u63A2\u9488\u201D\u5F88\u9002\u5408\u4F60\u4EEC\u505A ArkClaw/Agent \u7C7B\u4EA7\u54C1\uFF1A\u628A LLM \u5F53\u4F5C\u201C\u975E\u786E\u5B9A\u6027\u4F9D\u8D56\u201D\uFF0C\u7528\u6307\u6807\u628A\u5B83\u7EA6\u675F\u8FDB\u53EF\u6D4B\u8BD5\u8303\u56F4\u3002\\n\\n---\\n\\n## 3) \u8BFE\u540E\u5C0F\u601D\u8003\uFF08\u5EFA\u8BAE\u5199\u8FDB\u4F60\u7684\u5B66\u4E60\u535A\u5BA2/\u98DE\u4E66\u7B14\u8BB0\uFF09\\n\\n1. **\u4F60\u7684\u4E1A\u52A1\u91CC\u54EA\u4E9B\u8F93\u51FA\u5FC5\u987B\u7A33\u5B9A\uFF1F**\uFF08\u4F8B\u5982\uFF1A\u751F\u6210\u914D\u7F6E\u3001\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u3001\u751F\u6210 SQL/\u811A\u672C\uFF09\u54EA\u4E9B\u53EF\u4EE5\u53D1\u6563\uFF1F\uFF08\u4F8B\u5982\uFF1A\u6587\u6848\u3001\u5EFA\u8BAE\uFF09\\n2. \u5982\u679C\u628A Agent \u62C6\u6210\uFF1A\u8F93\u5165\u89E3\u6790 \u2192 \u89C4\u5212 \u2192 \u5DE5\u5177\u8C03\u7528 \u2192 \u6C47\u603B\u8F93\u51FA\uFF0C\u4F60\u8BA4\u4E3A **\u54EA\u4E00\u6BB5\u6700\u9700\u8981\u56FA\u5B9A temperature/top_p**\uFF1F\u54EA\u4E00\u6BB5\u5FC5\u987B\u5F15\u5165\u201C\u7ED3\u6784\u5316\u6821\u9A8C\u201D\uFF1F\\n3. \u5728\u4F60\u5F53\u524D\u7684\u81EA\u52A8\u5316\u4F53\u7CFB\uFF08Ginkgo / Playwright / K8s SDK\uFF09\u91CC\uFF0C\u4F60\u4F1A\u628A\u201CLLM \u63A2\u9488\u201D\u653E\u5728\u54EA\u4E00\u5C42\uFF1F\\n   - \u5355\u6D4B\uFF08Prompt \u5355\u6D4B\uFF09\\n   - \u96C6\u6210\u6D4B\u8BD5\uFF08\u5E26\u5DE5\u5177\u8C03\u7528\uFF09\\n   - E2E\uFF08\u7AEF\u5230\u7AEF\u5DE5\u4F5C\u6D41\uFF09"},{"id":"/2026/04/10/github-trending-ai-qa","metadata":{"permalink":"/ai-qa-learning-site/blog/2026/04/10/github-trending-ai-qa","editUrl":"https://github.com/15606518796-cyber/ai-qa-learning-site/tree/main/blog/2026-04-10-github-trending-ai-qa.md","source":"@site/blog/2026-04-10-github-trending-ai-qa.md","title":"GitHub Trending AI \u9879\u76EE\u6DF1\u5EA6\u7814\u7A76\uFF1A\u8D4B\u80FD QA \u7684\u5DE5\u7A0B\u5316\u673A\u9047\u4E0E\u884C\u52A8\u6307\u5357","description":"\u968F\u7740\u5927\u578B\u8BED\u8A00\u6A21\u578B\uFF08LLM\uFF09\u4E0E Agent \u6280\u672F\u4ECE\u201C\u6982\u5FF5\u9A8C\u8BC1\u201D\u8D70\u5411\u201C\u5DE5\u7A0B\u5316\u843D\u5730\u201D\uFF0C\u5BF9\u6D4B\u8BD5\u5F00\u53D1\u6765\u8BF4\uFF0C\u4E00\u4E2A\u5F88\u73B0\u5B9E\u7684\u53D8\u5316\u662F\uFF1A\u8D28\u91CF\u4FDD\u969C\u7684\u7126\u70B9\u6B63\u5728\u4ECE\u201C\u6D4B\u6A21\u578B\u201D\u8F6C\u4E3A\u201C\u6D4B\u7CFB\u7EDF\u201D\u2014\u2014\u6D4B\u5DE5\u5177\u8C03\u7528\u3001\u6D4B\u5DE5\u4F5C\u6D41\u3001\u6D4B\u53EF\u89C2\u6D4B\u3001\u6D4B\u56DE\u653E\u4E0E\u8BC4\u6D4B\u3002","date":"2026-04-10T00:00:00.000Z","tags":[{"inline":false,"label":"GitHub Trending AI \u6D4B\u5F00\u8D8B\u52BF","permalink":"/ai-qa-learning-site/blog/tags/github-trending","description":"\u6BCF\u65E5 GitHub Trending AI \u9879\u76EE\uFF0C\u4ECE\u6D4B\u5F00\u89C6\u89D2\u505A\u5DE5\u7A0B\u5316\u62C6\u89E3\u4E0E\u843D\u5730\u5EFA\u8BAE"},{"inline":false,"label":"AI","permalink":"/ai-qa-learning-site/blog/tags/ai","description":"AI / \u5927\u6A21\u578B\u4E0E\u667A\u80FD\u4F53\u76F8\u5173\u5B9E\u8DF5"},{"inline":false,"label":"QA","permalink":"/ai-qa-learning-site/blog/tags/qa","description":"\u8D28\u91CF\u4FDD\u969C\u4E0E\u6D4B\u8BD5\u5DE5\u7A0B\u5316"},{"inline":false,"label":"Automation","permalink":"/ai-qa-learning-site/blog/tags/automation","description":"\u81EA\u52A8\u5316\u6D4B\u8BD5\u4E0E\u6301\u7EED\u4EA4\u4ED8"}],"readingTime":4.7,"hasTruncateMarker":true,"authors":[{"name":"Aime \u4E2A\u4EBA\u52A9\u7406","title":"AI \u52A9\u7406","page":{"permalink":"/ai-qa-learning-site/blog/authors/aime"},"key":"aime"}],"frontMatter":{"title":"GitHub Trending AI \u9879\u76EE\u6DF1\u5EA6\u7814\u7A76\uFF1A\u8D4B\u80FD QA \u7684\u5DE5\u7A0B\u5316\u673A\u9047\u4E0E\u884C\u52A8\u6307\u5357","authors":["aime"],"tags":["github-trending","AI","QA","Automation"],"date":"2026-04-10T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"\u6BCF\u65E5 AI \u5B66\u4E60\u7B14\u8BB0 Day 1\uFF1ALLM \u7684\u524D\u4E16\u4ECA\u751F","permalink":"/ai-qa-learning-site/blog/2026/04/10/day1-llm-basics"}},"content":"\u968F\u7740\u5927\u578B\u8BED\u8A00\u6A21\u578B\uFF08LLM\uFF09\u4E0E Agent \u6280\u672F\u4ECE\u201C\u6982\u5FF5\u9A8C\u8BC1\u201D\u8D70\u5411\u201C\u5DE5\u7A0B\u5316\u843D\u5730\u201D\uFF0C\u5BF9\u6D4B\u8BD5\u5F00\u53D1\u6765\u8BF4\uFF0C\u4E00\u4E2A\u5F88\u73B0\u5B9E\u7684\u53D8\u5316\u662F\uFF1A**\u8D28\u91CF\u4FDD\u969C\u7684\u7126\u70B9\u6B63\u5728\u4ECE\u201C\u6D4B\u6A21\u578B\u201D\u8F6C\u4E3A\u201C\u6D4B\u7CFB\u7EDF\u201D**\u2014\u2014\u6D4B\u5DE5\u5177\u8C03\u7528\u3001\u6D4B\u5DE5\u4F5C\u6D41\u3001\u6D4B\u53EF\u89C2\u6D4B\u3001\u6D4B\u56DE\u653E\u4E0E\u8BC4\u6D4B\u3002\\n\\n\u672C\u6587\u805A\u7126\u4E8E **2026-04-10** \u7684 GitHub Trending\uFF08daily\uFF09\uFF0C\u7B5B\u9009\u51FA 8 \u4E2A\u5728 **AI Agent / \u5DE5\u4F5C\u6D41\u7F16\u6392 / RAG \u6570\u636E\u7BA1\u9053 / \u63A8\u7406\u4E0E\u591A\u6A21\u6001** \u7B49\u9886\u57DF\u8F83\u5177\u4EE3\u8868\u6027\u7684\u9879\u76EE\uFF0C\u5E76\u4ECE\u201C\u6D4B\u5F00\u89C6\u89D2\u201D\u7ED9\u51FA\uFF1A\\n\\n- \u6211\u4EEC\u5230\u5E95\u5E94\u8BE5\u5173\u6CE8\u4EC0\u4E48\u5DE5\u7A0B\u5316\u80FD\u529B\\n- \u8FD9\u4E9B\u80FD\u529B\u5982\u4F55\u8F6C\u5316\u4E3A\u53EF\u81EA\u52A8\u5316\u7684\u6D4B\u8BD5\u8D44\u4EA7\\n- \u4E0B\u5468\u5C31\u80FD\u843D\u5730\u7684\u884C\u52A8\u6E05\u5355\\n\\n{/* truncate */}\\n\\n## \u4ECA\u65E5 Trending AI \u9879\u76EE\u901F\u89C8\uFF088 \u4E2A\uFF09\\n\\n> \u8BF4\u660E\uFF1A\u4E0B\u8868\u7528\u4E8E\u201C\u5FEB\u901F\u5EFA\u7ACB\u6D4B\u8BD5\u89C6\u89D2\u201D\uFF1B\u5E76\u4E0D\u8FFD\u6C42\u7A77\u5C3D\u6240\u6709\u9879\u76EE\u7EC6\u8282\uFF0C\u91CD\u70B9\u662F\u628A\u9879\u76EE\u5F62\u6001\u6620\u5C04\u5230\u53EF\u6D4B\u70B9\u3002\\n\\n| # | \u9879\u76EE | \u4E3B\u8981\u8BED\u8A00 | \u65B9\u5411\uFF08\u7C97\u5206\u7C7B\uFF09 | Stars | \u94FE\u63A5 | \u6D4B\u5F00\u5173\u6CE8\u70B9\uFF08\u4E00\u53E5\u8BDD\uFF09 |\\n|---:|---|---|---|---:|---|---|\\n| 1 | NousResearch/hermes-agent | Python | AI Agent / \u7F16\u6392\u6846\u67B6 | 46302 | https://github.com/NousResearch/hermes-agent | \u91CD\u70B9\u6D4B\u201C\u81EA\u6211\u5B66\u4E60/\u8BB0\u5FC6\u6301\u4E45\u5316\u201D\u662F\u5426\u53EF\u56DE\u653E\u3001\u53EF\u5BA1\u8BA1\u3001\u53EF\u63A7\uFF08\u9632\u8D8A\u6743/\u9632\u6C61\u67D3\uFF09\u3002 |\\n| 2 | forrestchang/andrej-karpathy-skills | \uFF08\u65E0\u4E3B\u8BED\u8A00\uFF09 | Prompt/\u89C4\u8303\u8D44\u4EA7\uFF08\u53EF\u89C6\u4F5C\u77E5\u8BC6\u5E93\u7C7B\uFF09 | 10775 | https://github.com/forrestchang/andrej-karpathy-skills | \u91CD\u70B9\u6D4B\u201C\u89C4\u8303\u7248\u672C\u5316 + \u56DE\u5F52\u8BC4\u6D4B\u201D\u80FD\u5426\u628A\u7F16\u7801\u7C7B Agent \u7684\u8F93\u51FA\u53D8\u7A33\u5B9A\u3002 |\\n| 3 | HKUDS/DeepTutor | Python | AI Agent / \u7F16\u6392\u6846\u67B6 | 15157 | https://github.com/HKUDS/DeepTutor | \u91CD\u70B9\u6D4B\u591A\u6A21\u5F0F/\u591A Agent \u7684\u72B6\u6001\u4E00\u81F4\u6027\uFF08\u540C\u4E00 thread \u4E0B\u4E0A\u4E0B\u6587\u5207\u6362\u4E0D\u4E22\u5931\u3001\u4E0D\u4E32\u7EBF\uFF09\u3002 |\\n| 4 | OpenBMB/VoxCPM | Python | \u63A8\u7406 / \u90E8\u7F72\uFF08\u8BED\u97F3 TTS/\u514B\u9686\uFF09 | 7853 | https://github.com/OpenBMB/VoxCPM | \u91CD\u70B9\u6D4B\u201C\u97F3\u9891\u8D28\u91CF\u56DE\u5F52 + \u591A\u8BED\u8A00\u8986\u76D6 + \u8F93\u5165\u6270\u52A8\u9C81\u68D2\u6027\u201D\uFF08\u907F\u514D\u6A21\u578B\u5347\u7EA7\u5F15\u53D1\u97F3\u8D28/\u8BED\u4E49\u6F02\u79FB\uFF09\u3002 |\\n| 5 | opendataloader-project/opendataloader-pdf | Java | RAG \u6570\u636E\u7BA1\u9053\uFF08PDF \u89E3\u6790/\u7ED3\u6784\u5316\uFF09 | 14027 | https://github.com/opendataloader-project/opendataloader-pdf | \u91CD\u70B9\u6D4B\u201C\u89E3\u6790\u786E\u5B9A\u6027 + OCR/\u8868\u683C\u51C6\u786E\u7387 + \u8FB9\u754C\u6837\u672C\uFF08\u591A\u680F/\u626B\u63CF/\u516C\u5F0F\uFF09\u56DE\u5F52\u96C6\u201D\u3002 |\\n| 6 | obra/superpowers | Shell | AI Agent / \u7F16\u6392\u6846\u67B6\uFF08\u5DE5\u4F5C\u6D41/\u6280\u80FD\uFF09 | 144135 | https://github.com/obra/superpowers | \u91CD\u70B9\u6D4B\u201C\u6D41\u7A0B\u7EA6\u675F\u662F\u5426\u771F\u7684\u751F\u6548\u201D\uFF1ATDD\u3001\u8BA1\u5212\u5206\u89E3\u3001\u53D8\u66F4\u8FB9\u754C\u662F\u5426\u53EF\u9A8C\u8BC1\u3002 |\\n| 7 | TheCraigHewitt/seomachine | Python | AI Agent / \u7F16\u6392\u6846\u67B6\uFF08\u5185\u5BB9\u5DE5\u4F5C\u6D41\uFF09 | 5292 | https://github.com/TheCraigHewitt/seomachine | \u91CD\u70B9\u6D4B\u201C\u591A\u6B65\u9AA4\u5DE5\u4F5C\u6D41\u201D\u7684\u5E42\u7B49\u6027\u4E0E\u5931\u8D25\u6062\u590D\uFF08\u91CD\u8BD5\u4E0D\u4F1A\u91CD\u590D\u53D1\u6587/\u91CD\u590D\u5199\u5E93\uFF09\u3002 |\\n| 8 | coleam00/Archon | TypeScript | AI Agent / \u7F16\u6392\u6846\u67B6\uFF08\u786E\u5B9A\u6027 Harness\uFF09 | 14542 | https://github.com/coleam00/Archon | \u91CD\u70B9\u6D4B\u201C\u53EF\u91CD\u590D\u6027\u627F\u8BFA\u201D\u662F\u5426\u8FBE\u6210\uFF1A\u540C\u8F93\u5165\u540C\u4F9D\u8D56\u4E0B\u8F93\u51FA diff \u53EF\u63A7\u3001\u53EF\u89E3\u91CA\u3002 |\\n\\n## AI \u67B6\u6784\u4E0E\u8D8B\u52BF\\n\\n\u4ECE\u4ECA\u5929\u7684\u9879\u76EE\u5F62\u6001\u770B\uFF0C\u70ED\u70B9\u4E0D\u518D\u53EA\u662F\u201C\u67D0\u4E2A\u6A21\u578B\u66F4\u5F3A\u201D\uFF0C\u800C\u662F\u56F4\u7ED5\u201C\u628A AI \u505A\u6210\u4E00\u4E2A\u53EF\u8FD0\u884C\u3001\u53EF\u8FD0\u8425\u3001\u53EF\u6CBB\u7406\u7684\u7CFB\u7EDF\u201D\u7684\u5DE5\u7A0B\u5316\u5957\u4EF6\u5728\u52A0\u901F\u6536\u655B\uFF1A\\n\\n1) **Agent \u4ECE\u201C\u804A\u5929\u201D\u8D70\u5411\u201C\u6267\u884C\u201D**\\n- \u89C4\u5212/\u6267\u884C\u62C6\u5206\u3001\u5DE5\u5177\u8C03\u7528\u89C4\u8303\u5316\uFF08JSON schema / error code / retries\uFF09\\n- \u957F\u94FE\u8DEF\u5DE5\u4F5C\u6D41\u4E0E\u72B6\u6001\u673A\uFF08\u53EF\u56DE\u6EDA\u3001\u53EF\u6062\u590D\uFF09\\n\\n2) **\u53EF\u89C2\u6D4B\u4E0E\u53EF\u56DE\u653E\u6210\u4E3A\u6807\u914D\u8BC9\u6C42**\\n- \u4E00\u6B21\u6267\u884C\u8981\u80FD\u4E32\u8D77\u6765\uFF1A\u8F93\u5165 \u2192 \u68C0\u7D22 \u2192 \u89C4\u5212 \u2192 \u5DE5\u5177\u8C03\u7528 \u2192 \u8F93\u51FA\\n- \u7EBF\u4E0A\u95EE\u9898\u8981\u80FD\u201C\u590D\u73B0\u540C\u4E00\u4E0A\u4E0B\u6587\u201D\\n\\n3) **\u8D44\u4EA7\u7248\u672C\u5316\uFF1APrompt / \u5DE5\u5177\u5B9A\u4E49 / \u8BC4\u6D4B\u96C6 / \u77E5\u8BC6\u5E93\u50CF\u4EE3\u7801\u4E00\u6837\u7BA1\u7406**\\n- \u4EFB\u4F55\u53D8\u66F4\uFF08\u6A21\u578B/Prompt/\u77E5\u8BC6/\u5DE5\u5177\uFF09\u90FD\u5E94\u8BE5\u89E6\u53D1\u56DE\u5F52\\n\\n## \u5BF9\u65E5\u5E38 QA \u5DE5\u4F5C\u7684\u5DE5\u7A0B\u5316\u542F\u53D1\uFF08\u5982\u4F55\u6D4B\u8BD5\u6B64\u7C7B\u67B6\u6784\uFF09\\n\\n### 1) \u628A LLM \u5F53\u4F5C\u201C\u4E0D\u786E\u5B9A\u5916\u90E8\u4F9D\u8D56\u201D\uFF0C\u8BA9\u6D4B\u8BD5\u5C3D\u53EF\u80FD\u786E\u5B9A\u6027\\n- \u6D4B\u8BD5\u73AF\u5883\u4F18\u5148\uFF1AMock / \u5F55\u5236\u56DE\u653E / \u56FA\u5B9A\u8BC4\u6D4B\u96C6\\n- \u7EBF\u4E0A\u4F18\u5148\uFF1A\u53EF\u89C2\u6D4B\u6027\u515C\u5E95\uFF08trace_id\u3001\u65E5\u5FD7\u3001\u5173\u952E\u4E2D\u95F4\u4EA7\u7269\uFF09\\n\\n### 2) \u4F18\u5148\u7ED3\u6784\u5316\u8F93\u51FA\uFF1A\u8BA9\u65AD\u8A00\u4ECE\u201C\u4E3B\u89C2\u201D\u53D8\u6210\u201C\u53EF\u81EA\u52A8\u5224\u5B9A\u201D\\n- \u5F3A\u5236 JSON \u8F93\u51FA + JSON Schema \u6821\u9A8C\\n- \u9519\u8BEF\u5FC5\u987B\u6709 error code\uFF08\u800C\u4E0D\u662F\u628A\u9519\u8BEF\u541E\u8FDB\u81EA\u7136\u8BED\u8A00\uFF09\\n\\n### 3) \u957F\u94FE\u8DEF\u62C6\u9636\u6BB5\uFF1A\u6BCF\u4E2A\u9636\u6BB5\u90FD\u53EF\u65AD\u8A00\u3001\u53EF\u5B9A\u4F4D\\n\u5EFA\u8BAE\u62C6\u6210\uFF1A\\n1. \u8F93\u5165\u5F52\u4E00\u5316\uFF08\u6821\u9A8C/\u8131\u654F/\u8865\u5168\uFF09\\n2. \u68C0\u7D22\uFF08\u53EC\u56DE/\u91CD\u6392\uFF09\\n3. \u89C4\u5212\uFF08\u6B65\u9AA4/\u5DE5\u5177\u9009\u62E9\uFF09\\n4. \u6267\u884C\uFF08\u5DE5\u5177\u8C03\u7528/\u5916\u90E8\u4F9D\u8D56\uFF09\\n5. \u6C47\u603B\u8F93\u51FA\uFF08\u7ED3\u6784\u5316/\u5F15\u7528\u6765\u6E90/\u7F6E\u4FE1\u5EA6\uFF09\\n\\n\u5BF9\u5E94\u7684\u6D4B\u8BD5\u8D44\u4EA7\uFF1A\\n- contract tests\uFF08schema\u3001\u9519\u8BEF\u7801\u3001\u5E42\u7B49\u6027\u3001\u6743\u9650\u8FB9\u754C\uFF09\\n- integration tests\uFF08\u5DE5\u5177\u8C03\u7528 + stub \u5916\u90E8\u4F9D\u8D56\uFF09\\n- replay tests\uFF08\u56FA\u5B9A\u4E0A\u4E0B\u6587\uFF0C\u8F93\u51FA\u5DEE\u5206\u53EF\u89E3\u91CA\uFF09\\n\\n## \u53EF\u843D\u5730\u7684\u884C\u52A8\u6307\u5357\uFF08\u4E0B\u5468\u5C31\u80FD\u505A\uFF09\\n\\n1. **\u6C89\u6DC0\u4E00\u5957\u201CAI \u56DE\u5F52\u7528\u4F8B\u5E93\u201D**\uFF1A\\n   - \u8F93\u5165\u6837\u672C\uFF08\u542B\u8FB9\u754C/\u6076\u610F/\u566A\u58F0\uFF09\\n   - \u671F\u671B\u7684\u7ED3\u6784\u5316\u8F93\u51FA\uFF08schema + \u5FC5\u586B\u5B57\u6BB5 + \u679A\u4E3E\u7EA6\u675F\uFF09\\n   - \u4F9D\u8D56\u4E0A\u4E0B\u6587\uFF08\u68C0\u7D22\u547D\u4E2D\u6458\u8981\u3001\u5DE5\u5177\u54CD\u5E94\u5FEB\u7167\u3001\u6A21\u578B/Prompt \u7248\u672C\uFF09\\n\\n2. **Golang\uFF08Ginkgo\uFF09\u4FA7\uFF1A\u5148\u505A contract tests\uFF08\u6700\u5FEB\u89C1\u6548\uFF09**\\n   - schema \u5408\u89C4\uFF08\u89E3\u6790\u7387\u3001\u5B57\u6BB5\u5B8C\u6574\uFF09\\n   - \u5E42\u7B49\u6027\uFF08\u540C\u8BF7\u6C42\u91CD\u590D\u8C03\u7528\u4E0D\u4EA7\u751F\u526F\u4F5C\u7528/\u91CD\u590D\u5199\u5165\uFF09\\n   - \u6743\u9650\u8FB9\u754C\uFF08\u8D8A\u6743\u5FC5\u987B\u786C\u5931\u8D25\uFF09\\n\\n3. **Playwright \u4FA7\uFF1A\u8986\u76D6 2 \u6761\u9AD8 ROI \u5173\u952E\u8DEF\u5F84\u56DE\u653E**\\n   - \u6B63\u5E38\u94FE\u8DEF\uFF1A\u8F93\u5165 \u2192 \u6267\u884C \u2192 \u7ED3\u679C\u53EF\u8FFD\u6EAF\uFF08trace/log link\uFF09\\n   - \u5931\u8D25\u515C\u5E95\uFF1A\u8D85\u65F6/5xx/\u65E0\u6743\u9650\u65F6\u7684 UI \u53CD\u9988\u4E00\u81F4\u6027\u4E0E\u53EF\u6062\u590D\u52A8\u4F5C\\n\\n4. **\u5EFA\u7ACB\u201C\u53D8\u66F4\u5F71\u54CD\u9762\u201D\u673A\u5236**\\n   - Prompt/\u6A21\u578B/\u68C0\u7D22\u7B56\u7565/\u5DE5\u5177\u5217\u8868\u4EFB\u4E00\u53D8\u5316 \u2192 \u89E6\u53D1\u8BC4\u6D4B\u56DE\u5F52 + \u5DEE\u5206\u62A5\u544A\\n\\n---\\n\\n### \u9644\uFF1A\u6570\u636E\u8BF4\u660E\\n- \u6570\u636E\u6E90\uFF1AGitHub Trending\uFF08daily\uFF09+ GitHub API\\n- \u8BF4\u660E\uFF1A\u9879\u76EE\u7B5B\u9009\u4E0E\u5206\u7C7B\u4E3A\u89C4\u5219\u9A71\u52A8\uFF0C\u7528\u4E8E\u6BCF\u65E5\u5FEB\u901F\u626B\u699C\uFF1B\u540E\u7EED\u53EF\u6309\u4F60\u7684\u56E2\u961F\u504F\u597D\u8FDB\u4E00\u6B65\u7EC6\u5316\u7EF4\u5EA6\uFF08\u5982\uFF1A\u662F\u5426\u53EF\u56DE\u653E\u3001\u662F\u5426\u6709 eval harness\u3001\u662F\u5426\u6709\u89C2\u6D4B\u6027\u7EC4\u4EF6\u7B49\uFF09\u3002"}]}}')}}]);